/// [Apple's documentation](https://developer.apple.com/documentation/carbon/thememetric?language=objc)
pub type ThemeMetric = u32;

/// # Safety
///
/// `out_metric` must be a valid pointer.
#[inline]
pub unsafe fn GetThemeMetric(in_metric: ThemeMetric, out_metric: *mut i32) -> OSStatus {
    extern "C-unwind" {
        fn GetThemeMetric(in_metric: ThemeMetric, out_metric: *mut i32) -> OSStatus;
    }
    unsafe { GetThemeMetric(in_metric, out_metric) }
}

/// # Safety
///
/// `out_identifier` might not allow `None`.
#[inline]
pub unsafe fn CopyThemeIdentifier(
    out_identifier: Option<&mut Option<CFRetained<CFString>>>,
) -> OSStatus {
    extern "C-unwind" {
        fn CopyThemeIdentifier(
            out_identifier: Option<&mut Option<CFRetained<CFString>>>,
        ) -> OSStatus;
    }
    if let Some(out_identifier) = out_identifier.as_ref() {
        assert!(
            out_identifier.is_none(),
            "parameter `out_identifier` must point to `None` on entry"
        );
    };
    unsafe { CopyThemeIdentifier(out_identifier) }
}

